import React from "react";
import { Flex, Text } from "../../_compat";
import {
    IoAlertCircle,
    IoCheckmarkCircle,
    IoCloseCircle,
    IoInformationCircle
} from "react-icons/io5";
import type { IAlertComponent } from "@lmb-it/kitsconcerto-types";
import { useKitsTheme } from "../../contexts/Theme";

const icons: Record<string, React.ReactNode> = {
    error: <IoCloseCircle size={22} />,
    success: <IoCheckmarkCircle size={22} />,
    warning: <IoAlertCircle size={22} />,
    info: <IoInformationCircle size={22} />,
};

const Alert: React.FC<IAlertComponent> = ({
                                          status = "info",
                                          variant = "subtle",
                                          children,
                                          className = "",
                                          ...props
                                      }) => {
    const { resolveToken, theme } = useKitsTheme();
    const primary = resolveToken('primary');

    const statusColors: Record<string, { bg: string; text: string; border: string; solid: string }> = {
        error: { bg: resolveToken('red.100'), text: resolveToken('red.700'), border: resolveToken('red.500'), solid: resolveToken('red.600') },
        success: { bg: resolveToken('green.100'), text: resolveToken('green.700'), border: resolveToken('green.500'), solid: resolveToken('green.600') },
        warning: { bg: resolveToken('yellow.100'), text: resolveToken('yellow.700'), border: resolveToken('yellow.500'), solid: resolveToken('yellow.600') },
        info: { bg: resolveToken('blue.100'), text: resolveToken('blue.700'), border: resolveToken('blue.500'), solid: resolveToken('blue.600') },
        brand: { bg: resolveToken('cyan.100'), text: resolveToken('cyan.700'), border: primary, solid: primary },
    };

    const colors = statusColors[status];
    let bgColor: string | undefined;
    let fontColor: string | undefined;
    const borderStyle: React.CSSProperties = {};

    if (variant === "subtle") {
        bgColor = colors.bg;
        fontColor = colors.text;
    } else if (variant === "solid") {
        bgColor = colors.solid;
        fontColor = "white";
    } else if (variant === "left-accent") {
        bgColor = colors.bg;
        fontColor = colors.text;
        borderStyle.borderLeft = `4px solid`;
        borderStyle.borderLeftColor = colors.border;
    } else if (variant === "top-accent") {
        bgColor = colors.bg;
        fontColor = colors.text;
        borderStyle.borderTop = `4px solid`;
        borderStyle.borderTopColor = colors.border;
    }

    return (
        <Flex
            flexDirection="row"
            alignItems="center"
            gap="0.5rem"
            p="0.75rem"
            borderRadius="0.5rem"
            bgColor={bgColor}
            fontColor={fontColor}
            className={className}
            style={borderStyle}
            {...props}
        >
            {children}
        </Flex>
    );
};

export const AlertIcon: React.FC<{ status: IAlertComponent["status"] }> = ({ status = "info" }) => {
    const { theme } = useKitsTheme();
    if (status === 'brand' && theme.config.logo) return <>{theme.config.logo}</>;
    return <>{icons[status!]}</>;
};

export const AlertTitle: React.FC<{ children: React.ReactNode }> = ({ children }) => (
    <Text fontWeight="bold">{children}</Text>
);

export const AlertDescription: React.FC<{ children: React.ReactNode }> = ({ children }) => (
    <Text fontSize="0.875rem">{children}</Text>
);

export default Alert;
